Node* reverseDLL(Node* head) {
    if (head == NULL) return NULL;

    Node* curr = head;
    Node* prevNode = NULL;

    while (curr != NULL) {
        prevNode = curr->prev;      // store prev
        curr->prev = curr->next;    // swap prev
        curr->next = prevNode;      // swap next

        curr = curr->prev;          // move forward
    }

    if (prevNode != NULL)
        head = prevNode->prev;

    return head;
}

