Node* reverseDLL(Node* head) {
    if (head == NULL) return NULL;

    Node* curr = head;
    Node* prevNode = NULL;

    while (curr != NULL) {
        prevNode = curr->prev;      // store previous
        curr->prev = curr->next;    // swap prev
        curr->next = prevNode;      // swap next
        curr = curr->prev;          // move to next
    }

    // After loop, prevNode is at old head; new head = prevNode->prev
    if (prevNode != NULL)
        head = prevNode->prev;

    return head;
}

